func TestClientReportScopedToOneClient(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelClientReportCmd, "Acme Corp", "--db", dbPath)

	var report clientReport
	mustUnmarshal(t, out, &report)

	if len(report.Devices) != 1 || report.Devices[0].SerialNumber != "DT01" {
		t.Fatalf("Devices = %+v, want exactly DT01", report.Devices)
	}
	if report.TotalAgents != 2 {
		t.Fatalf("TotalAgents = %d, want 2 (Globex agents must not leak in)", report.TotalAgents)
	}
	for _, a := range report.Agents {
		if a.DeviceSerialNumber != "DT01" {
			t.Fatalf("agent %q from foreign device %q leaked into the report", a.AgentName, a.DeviceSerialNumber)
		}
	}
	if report.ScreenshotPassPct != 50 {
		t.Fatalf("ScreenshotPassPct = %v, want 50", report.ScreenshotPassPct)
	}
	if report.OpenAlerts != 3 {
		t.Fatalf("OpenAlerts = %d, want 3", report.OpenAlerts)
	}
	if report.Note != "" {
		t.Fatalf("unexpected note for a matched client: %q", report.Note)
	}
}

func TestClientReportCaseInsensitiveMatch(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelClientReportCmd, "acme corp", "--db", dbPath)

	var report clientReport
	mustUnmarshal(t, out, &report)
	if len(report.Devices) != 1 {
		t.Fatalf("case-insensitive match failed: devices = %+v", report.Devices)
	}
}

func TestClientReportUnknownClientIsHonestlyEmpty(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelClientReportCmd, "No Such Client", "--db", dbPath)

	var report clientReport
	mustUnmarshal(t, out, &report)
	if len(report.Devices) != 0 || report.TotalAgents != 0 {
		t.Fatalf("unknown client must return empty report, got %+v", report)
	}
	if !strings.Contains(report.Note, "no synced devices or agents matched") {
		t.Fatalf("empty report must carry an honest note, got %q", report.Note)
	}
}
